def has_cycle(graph):
    visited = set()
    recStack = set()

    def dfs(node):
        if node in recStack:
            return True
        if node in visited:
            return False

        visited.add(node)
        recStack.add(node)

        for neighbour in graph.get(node, []):
            dfs(neighbour)

        recStack.remove(node)
        return False

    for vertex in graph:
        if dfs(vertex):
            return True
    return False

